You can use the URL API to parse the URL and then use a regular expression to remove the username and password from the URL. Here's an example of how you can do this in JavaScript:

```javascript
function stripAuth(url) {
    const parsedUrl = new URL(url);
    const authRegex = /^https?:\/\/([^:]+):([^:]+)@/;

    if (parsedUrl.username && parsedUrl.password) {
        const match = parsedUrl.href.match(authRegex);
        if (match) {
            parsedUrl.username = '';
            parsedUrl.password = '';
            parsedUrl.href = parsedUrl.origin + parsedUrl.pathname + parsedUrl.search + parsedUrl.hash;
        }
    } else if (parsedUrl.username) {
        const match = parsedUrl.href.match(authRegex);
        if (match) {
            parsedUrl.username = '';
            parsedUrl.href = parsedUrl.origin + parsedUrl.pathname + parsedUrl.search + parsedUrl.hash;
        }
    }

    return parsedUrl.href;
}

// Example usage:
