**Using HttpClient**

```csharp
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.Net.Http;
using System.Net.Http.Headers;
using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet]
    public async Task<IActionResult> Get([FromUri] string url)
    {
        var httpClient = _httpClientFactory.CreateClient();
        var response = await httpClient.GetAsync(url);

        if (response.IsSuccessStatusCode)
        {
            return new ObjectResult(await response.Content.ReadAsStringAsync());
        }
        else
        {
            return StatusCode((int)response.StatusCode);
        }
    }
}
```

**Using IHttpClientFactory**

In the above example, we're using the `IHttpClientFactory` to create a new instance of `HttpClient`. This is recommended over creating a new instance of `HttpClient` every time you need to make a request.

