Here's an example of an updated `BaseRepository` where you can find by a dynamic field. We'll use the `Expression` class from `System.Linq.Expressions` to dynamically build the expression.

```csharp
using System;
using System.Linq;
using System.Linq.Expressions;

public abstract class BaseRepository<T> where T : class
{
    protected readonly DbContext _context;

    public BaseRepository(DbContext context)
    {
        _context = context;
    }

    public virtual IQueryable<T> GetAll()
    {
        return _context.Set<T>();
    }

    public virtual IQueryable<T> FindBy(Expression<Func<T, bool>> expression)
    {
        return _context.Set<T>().Where(expression);
    }

    public virtual IQueryable<T> FindByDynamic(string propertyName, object value)
    {
        var parameter = Expression.Parameter(typeof(T));
        var property = Expression.Property(parameter, propertyName);
        var constant = Expression.Constant(value);
        var equals = Expression.Equal(property, constant);
        var lambda = Expression.Lambda<Func<T, bool>>(equals, parameter);
        return FindBy(lambda);
    }
}
```

